import React from "react"
import { useState, useEffect, useRef } from "react"
import { graphql, Link } from "gatsby"

import Layout from "../components/layout"
import Seo from "../components/seo"
import Categories from "../components/custom/category-component"

// SitePageContext로부터 context를 이용해 전달한 값들의 type을 얻을 수 있다.

const Category = ({ data, location, pageContext }) => {
  const { title } = data.site.siteMetadata
  const { category } = pageContext // gatsby-node.js의 createPage에서 넣어준 카테고리 이름.
  const { edges, totalCount } = data.allMarkdownRemark
  const tagHeader = `${totalCount} post${
    totalCount === 1 ? "" : "s"
  } in "${category}"`

  const [categoryName, setCategoryName] = useState()

  const viewport = useRef(null)
  const target = useRef(null)

  useEffect(() => {
    const handleIntersection = entires => {
      entires.forEach(entry => {
        if (!entry.isIntersecting) {
          setCategoryName("category-comp-fixed")
        } else {
          setCategoryName("category-comp-absolute")
        }
      })
    }

    const io = new IntersectionObserver(handleIntersection)

    io.observe(target.current)

    return () => io.disconnect()
  }, [categoryName])

  return (
    <div className="category-page" ref={viewport}>
      <Layout location={location} title={title}>
        <Seo title={title} />
        <Categories name={categoryName} />
        <h1 className="header">{tagHeader}</h1>

        <ul>
          {/* 각 카테고리에 해당하는 포스트의 목록을 출력한다. */}
          {edges.map(({ node }) => {
            const { slug } = node.fields
            const { title } = node.frontmatter
            return (
              <li key={slug} ref={target}>
                <Link to={slug}>{title}</Link>
              </li>
            )
          })}
        </ul>
        <Link to="/">Go back to the homepage</Link>
      </Layout>
    </div>
  )
}

export default Category

// 쿼리의 argument인 $category는 page context로 전달 받는다.
export const pageQuery = graphql`
  query Category($category: String) {
    site {
      siteMetadata {
        title
      }
    }
    allMarkdownRemark(
      limit: 2000
      sort: { fields: [frontmatter___date], order: DESC }
      filter: { frontmatter: { categories: { in: [$category] } } }
    ) {
      totalCount
      edges {
        node {
          fields {
            slug
          }
          frontmatter {
            title
          }
        }
      }
    }
  }
`
